\begin{lemma}
If the method under consideration is stable then $a_1 > 0$ and
$a_i \ge 0$, for $i = 2, 3, \dots, k$.
\end{lemma}

context_latex:
\paragraph{Context}
The lemma concerns a stable linear multistep method for ODEs, where \(a(z)\) and \(b(z)\) are polynomials of degree \(k\) derived from the generating polynomials \(\alpha\) and \(\beta\). The coefficients \(a_i\) are defined via the expansion of \(a(z)\).

Variables:
\begin{itemize}
    \item \(a(z) = a_0 + a_1 z + a_2 z^2 + \dots + a_k z^k = (1+z)^k \alpha\!\left(\frac{1-z}{1+z}\right)\)
    \item \(b(z) = b_0 + b_1 z + b_2 z^2 + \dots + b_k z^k = (1+z)^k \beta\!\left(\frac{1-z}{1+z}\right)\)
    \item \(a_0, a_1, \dots, a_k\): coefficients of the polynomial \(a(z)\)
    \item \(k\): degree of the polynomials \(a(z)\) and \(b(z)\)
    \item \(p\): order of the method, such that certain expressions are \(O(z^p)\)
\end{itemize}

Referenced equation:
\begin{equation}
(1+z)^k \alpha\!\left(\frac{1-z}{1+z}\right) \cdot \frac{z}{\log\!\left(\frac{1+z}{1-z}\right)} - (1+z)^k \beta\!\left(\frac{1-z}{1+z}\right) = O(z^p) \tag{441a}
\end{equation}
